(() => {
    enum Color {
      Red,
      Green = 'green',
      Blue = 2,
    }
    return {
      build: () => {
        const check = typia.createIs<Color>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<Color>();
        return (v) => val(v).success;
      },
    };
  })()
